// ============================================
// Constants
// ============================================
object PrefsConstants {
    const val PREFS_NAME = "biometric_auth_prefs"
    const val KEY_AUTHENTICATED = "is_authenticated"
    const val KEY_BIOMETRIC_ENABLED = "biometric_enabled"
    const val KEY_STORED_PASSWORD = "stored_password"
}

// ============================================
// AuthPreferencesManager - Handles SharedPreferences
// ============================================
class AuthPreferencesManager(context: Context) {

    private val sharedPreferences: SharedPreferences =
        context.getSharedPreferences(PrefsConstants.PREFS_NAME, Context.MODE_PRIVATE)

    var isAuthenticated: Boolean
        get() = sharedPreferences.getBoolean(PrefsConstants.KEY_AUTHENTICATED, false)
        set(value) {
            sharedPreferences.edit().putBoolean(PrefsConstants.KEY_AUTHENTICATED, value).apply()
        }

    var isBiometricEnabled: Boolean
        get() = sharedPreferences.getBoolean(PrefsConstants.KEY_BIOMETRIC_ENABLED, false)
        set(value) {
            sharedPreferences.edit().putBoolean(PrefsConstants.KEY_BIOMETRIC_ENABLED, value).apply()
        }

    var storedPassword: String?
        get() = sharedPreferences.getString(PrefsConstants.KEY_STORED_PASSWORD, null)
        set(value) {
            sharedPreferences.edit().putString(PrefsConstants.KEY_STORED_PASSWORD, value).apply()
        }

    fun clearAuth() {
        sharedPreferences.edit()
            .putBoolean(PrefsConstants.KEY_AUTHENTICATED, false)
            .apply()
    }

    fun clearAll() {
        sharedPreferences.edit().clear().apply()
    }
}

// ============================================
// BiometricHelper - Manages BiometricPrompt setup
// ============================================
class BiometricHelper(private val activity: AppCompatActivity) {

    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo
    private val executor: Executor = ContextCompat.getMainExecutor(activity)

    enum class BiometricStatus {
        AVAILABLE,
        NO_HARDWARE,
        HARDWARE_UNAVAILABLE,
        NONE_ENROLLED,
        UNKNOWN_ERROR
    }

    fun checkBiometricAvailability(): BiometricStatus {
        val biometricManager = BiometricManager.from(activity)
        return when (biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG)) {
            BiometricManager.BIOMETRIC_SUCCESS -> BiometricStatus.AVAILABLE
            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE -> BiometricStatus.NO_HARDWARE
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE -> BiometricStatus.HARDWARE_UNAVAILABLE
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> BiometricStatus.NONE_ENROLLED
            else -> BiometricStatus.UNKNOWN_ERROR
        }
    }

    fun setupBiometricPrompt(
        onSuccess: () -> Unit,
        onError: (errorCode: Int, errString: String) -> Unit,
        onFailed: () -> Unit
    ) {
        val callback = object : BiometricPrompt.AuthenticationCallback() {
            override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                super.onAuthenticationSucceeded(result)
                onSuccess()
            }

            override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                super.onAuthenticationError(errorCode, errString)
                onError(errorCode, errString.toString())
            }

            override fun onAuthenticationFailed() {
                super.onAuthenticationFailed()
                onFailed()
            }
        }

        biometricPrompt = BiometricPrompt(activity, executor, callback)

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Biometric Authentication")
            .setSubtitle("Use your fingerprint to sign in")
            .setDescription("Place your finger on the sensor to verify your identity")
            .setNegativeButtonText("Use Password Instead")
            .setConfirmationRequired(false)
            .build()
    }

    fun authenticate() {
        biometricPrompt.authenticate(promptInfo)
    }

    fun cancelAuthentication() {
        if (::biometricPrompt.isInitialized) {
            biometricPrompt.cancelAuthentication()
        }
    }
}

// ============================================
// SplashActivity - Entry point, checks auth state
// ============================================
class SplashActivity : AppCompatActivity() {

    private lateinit var authPrefs: AuthPreferencesManager

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        authPrefs = AuthPreferencesManager(this)

        if (authPrefs.isAuthenticated && authPrefs.isBiometricEnabled) {
            // User was previously authenticated with biometric, go to biometric verification
            navigateToBiometricLogin()
        } else if (authPrefs.isAuthenticated) {
            // User is authenticated (session active), skip login
            navigateToMain()
        } else {
            // First time or logged out, go to login
            navigateToLogin()
        }
    }

    private fun navigateToBiometricLogin() {
        val intent = Intent(this, LoginActivity::class.java)
        intent.putExtra("show_biometric", true)
        startActivity(intent)
        finish()
    }

    private fun navigateToMain() {
        startActivity(Intent(this, MainActivity::class.java))
        finish()
    }

    private fun navigateToLogin() {
        startActivity(Intent(this, LoginActivity::class.java))
        finish()
    }
}

