    private val DEFAULT_PASSWORD = "password123"

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        authPrefs = AuthPreferencesManager(this)
        biometricHelper = BiometricHelper(this)

        // Setup simple layout programmatically
        setupUI()

