        val showBiometric = intent.getBooleanExtra("show_biometric", false)
        if (showBiometric && authPrefs.isBiometricEnabled) {
            showBiometricPrompt()
        }

        // Setup click listeners
        setupListeners()
    }

    private fun setupUI() {
        val layout = android.widget.LinearLayout(this).apply {
            orientation = android.widget.LinearLayout.VERTICAL
            setPadding(64, 128, 64, 64)
            gravity = android.view.Gravity.CENTER_HORIZONTAL
        }

        val tvTitle = TextView(this).apply {
            text = "Welcome Back"
            textSize = 28f
            setTypeface(null, android.graphics.Typeface.BOLD)
            gravity = android.view.Gravity.CENTER
        }
        layout.addView(tvTitle, android.widget.LinearLayout.LayoutParams(
            android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
        ).apply { bottomMargin = 48 })

        tvStatus = TextView(this).apply {
            text = ""
            textSize = 14f
            gravity = android.view.Gravity.CENTER
            setTextColor(android.graphics.Color.RED)
        }
        layout.addView(tvStatus, android.widget.LinearLayout.LayoutParams(
