    private fun setupBiometric() {
        biometricHelper.setupBiometricPrompt(
            onSuccess = {
                onAuthenticationSuccess(viaBiometric = true)
            },
            onError = { errorCode, errString ->
                when (errorCode) {
                    BiometricPrompt.ERROR_NEGATIVE_BUTTON -> {
                        // User chose to use password instead
                        tvStatus.text = "Please use your password to sign in"
                        tvStatus.setTextColor(android.graphics.Color.parseColor("#FF6600"))
                        showPasswordFields()
                    }
                    BiometricPrompt.ERROR_USER_CANCELED -> {
                        tvStatus.text = "Authentication cancelled"
                        tvStatus.setTextColor(android.graphics.Color.GRAY)
                    }
                    BiometricPrompt.ERROR_LOCKOUT -> {
                        tvStatus.text = "Too many attempts. Biometric locked. Use password."
                        tvStatus.setTextColor(android.graphics.Color.RED)
                        showPasswordFields()
                        btnBiometric.isEnabled = false
                    }
                    BiometricPrompt.ERROR_LOCKOUT_PERMANENT -> {
                        tvStatus.text = "Biometric permanently locked. Use password."
                        tvStatus.setTextColor(android.graphics.Color.RED)
                        showPasswordFields()
                        btnBiometric.isEnabled = false
                    }
                    else -> {
                        tvStatus.text = "Authentication error: $errString"
                        tvStatus.setTextColor(android.graphics.Color.RED)
                    }
                }
            },
            onFailed = {
                tvStatus.text = "Fingerprint not recognized. Try again."
                tvStatus.setTextColor(android.graphics.Color.RED)
            }
        )
    }

    private fun setupListeners() {
        btnLogin.setOnClickListener {
            performPasswordLogin()
        }

        btnBiometric.setOnClickListener {
            showBiometricPrompt()
        }
    }

    private fun performPasswordLogin() {
        val username = etUsername.text.toString().trim()
        val password = etPassword.text.toString().trim()

        if (username.isEmpty() || password.isEmpty()) {
            tvStatus.text = "Please enter username and password"
            tvStatus.setTextColor(android.graphics.Color.RED)
            return
        }

        // Simple validation (replace with real server authentication)
        if (username == DEFAULT_USERNAME && password == DEFAULT_PASSWORD) {
            // Check if biometric is available and not yet enabled
            val biometricStatus = biometricHelper.checkBiometricAvailability()
            if (biometricStatus == BiometricHelper.BiometricStatus.AVAILABLE && !authPrefs.isBiometricEnabled) {
                showEnableBiometricDialog()
            } else {
                onAuthenticationSuccess(viaBiometric = false)
            }
        } else {
            tvStatus.text = "Invalid username or password"
            tvStatus.setTextColor(android.graphics.Color.RED)
            etPassword.text.clear()
        }
    }

    private fun showEnableBiometricDialog() {
        val dialog = androidx.appcompat.app.AlertDialog.Builder(this)
            .setTitle("Enable Fingerprint Login?")
            .setMessage("Would you like to use fingerprint authentication for faster sign-in next time?")
            .setPositiveButton("Yes, Enable") { _, _ ->
                authPrefs.isBiometricEnabled = true
                authPrefs.storedPassword = DEFAULT_PASSWORD // In production, store encrypted token
                Toast.makeText(this, "Fingerprint login enabled!", Toast.LENGTH_SHORT).show()
                onAuthenticationSuccess(viaBiometric = false)
            }
            .setNegativeButton("Not Now") { dialog, _ ->
                dialog.dismiss()
                onAuthenticationSuccess(viaBiometric = false)
            }
            .setCancelable(false)
            .create()
        dialog.show()
    }

    private fun showBiometricPrompt() {
        val status = biometricHelper.checkBiometricAvailability()
        when (status) {
            BiometricHelper.BiometricStatus.AVAILABLE -> {
                biometricHelper.authenticate()
            }
            BiometricHelper.BiometricStatus.NO_HARDWARE -> {
                tvStatus.text = "No biometric hardware available on this device"
                tvStatus.setTextColor(android.graphics.Color.RED)
                showPasswordFields()
            }
            BiometricHelper.BiometricStatus.HARDWARE_UNAVAILABLE -> {
                tvStatus.text = "Biometric hardware is currently unavailable"
                tvStatus.setTextColor(android.graphics.Color.RED)
                showPasswordFields()
            }
            BiometricHelper.BiometricStatus.NONE_ENROLLED -> {
                tvStatus.text = "No fingerprints enrolled. Please add a fingerprint in Settings."
                tvStatus.setTextColor(android.graphics.Color.parseColor("#FF6600"))
                showPasswordFields()
            }
            BiometricHelper.BiometricStatus.UNKNOWN_ERROR -> {
                tvStatus.text = "Biometric authentication unavailable"
                tvStatus.setTextColor(android.graphics.Color.RED)
                showPasswordFields()
            }
        }
    }

    private fun showPasswordFields() {
        etUsername.visibility = android.view.View.VISIBLE
        etPassword.visibility = android.view.View.VISIBLE
        btnLogin.visibility = android.view.View.VISIBLE
    }

    private fun updateBiometricButtonVisibility() {
        val biometricStatus = biometricHelper.checkBiometricAvailability()
        if (biometricStatus == BiometricHelper.BiometricStatus.AVAILABLE && authPrefs.isBiometricEnabled) {
            btnBiometric.visibility = android.view.View.VISIBLE
            // Optionally hide password fields initially when biometric is available
        } else if (biometricStatus == BiometricHelper.BiometricStatus.AVAILABLE) {
            btnBiometric.visibility = android.view.View.VISIBLE
            btnBiometric.text = "🔐 Setup Fingerprint Login"
        } else {
            btnBiometric.visibility = android.view.View.GONE
        }
    }

    private fun onAuthenticationSuccess(viaBiometric: Boolean) {
        authPrefs.isAuthenticated = true

        val method = if (viaBiometric) "fingerprint" else "password"
        Toast.makeText(this, "Welcome! Signed in via $method", Toast.LENGTH_SHORT).show()

        startActivity(Intent(this, MainActivity::class.java))
        finish()
    }

    override fun onDestroy() {
        super.onDestroy()
        biometricHelper.cancelAuthentication()
    }
}

// ============================================
// MainActivity - The main screen after authentication
// ============================================
class MainActivity : AppCompatActivity() {

    private lateinit var authPrefs: AuthPreferencesManager

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        authPrefs = AuthPreferencesManager(this)

        // Verify authentication
        if (!authPrefs.isAuthenticated) {
            navigateToLogin()
            return
        }

        setupUI()
    }

    private fun setupUI() {
        val layout = android.widget.LinearLayout(this).apply {
            orientation = android.widget.LinearLayout.VERTICAL
            setPadding(64, 128, 64, 64)
            gravity = android.view.Gravity.CENTER
        }

        val tvWelcome = TextView(this).apply {
            text = "🎉 Welcome to the App!"
            textSize = 24f
            setTypeface(null, android.graphics.Typeface.BOLD)
            gravity = android.view.Gravity.CENTER
        }
        layout.addView(tvWelcome, android.widget.LinearLayout.LayoutParams(
            android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
        ).apply { bottomMargin = 32 })

        val tvInfo = TextView(this).apply {
            text = "You are securely authenticated."
            textSize = 16f
            gravity = android.view.Gravity.CENTER
        }
        layout.addView(tvInfo, android.widget.LinearLayout.LayoutParams(
            android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
        ).apply { bottomMargin = 16 })

        val tvBiometricStatus = TextView(this).apply {
            val status = if (authPrefs.isBiometricEnabled) "✅ Enabled" else "❌ Disabled"
            text = "Fingerprint Login: $status"
            textSize = 14f
            gravity = android.view.Gravity.CENTER
            setTextColor(android.graphics.Color.GRAY)
        }
        layout.addView(tvBiometricStatus, android.widget.LinearLayout.LayoutParams(
            android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
        ).apply { bottomMargin = 48 })

        val btnToggleBiometric = Button(this).apply {
            text = if (authPrefs.isBiometricEnabled) "Disable Fingerprint Login" else "Enable Fingerprint Login"
            isAllCaps = false
        }
        btnToggleBiometric.setOnClickListener {
            val biometricHelper = BiometricHelper(this@MainActivity)
            val status = biometricHelper.checkBiometricAvailability()

            if (status != BiometricHelper.BiometricStatus.AVAILABLE) {
                Toast.makeText(this, "Biometric not available on this device", Toast.LENGTH_SHORT).show()
                return@setOnClickListener
            }

            authPrefs.isBiometricEnabled = !authPrefs.isBiometricEnabled
            val newStatus = if (authPrefs.isBiometricEnabled) "enabled" else "disabled"
            Toast.makeText(this, "Fingerprint login $newStatus", Toast.LENGTH_SHORT).show()

            tvBiometricStatus.text = "Fingerprint Login: ${if (authPrefs.isBiometricEnabled) "✅ Enabled" else "❌ Disabled"}"
            btnToggleBiometric.text = if (authPrefs.isBiometricEnabled) "Disable Fingerprint Login" else "Enable Fingerprint Login"
        }
        layout.addView(btnToggleBiometric, android.widget.LinearLayout.LayoutParams(
            android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
        ).apply { bottomMargin = 16 })

        val btnLogout = Button(this).apply {
            text = "Sign Out"
            isAllCaps = false
            setBackgroundColor(android.graphics.Color.parseColor("#FF4444"))
            setTextColor(android.graphics.Color.WHITE)
        }
        btnLogout.setOnClickListener {
            performLogout()
        }
        layout.addView(btnLogout, android.widget.LinearLayout.LayoutParams(
            android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
        ).apply { topMargin = 16 })

        val btnFullLogout = Button(this).apply {
            text = "Sign Out & Clear Biometric"
            isAllCaps = false
            setTextColor(android.graphics.Color.RED)
        }
        btnFullLogout.setOnClickListener {
            performFullLogout()
        }
        layout.addView(btnFullLogout, android.widget.LinearLayout.LayoutParams(
            android.widget.LinearLayout.LayoutParams.MATCH_PARENT,
            android.widget.LinearLayout.LayoutParams.WRAP_CONTENT
        ).apply { topMargin = 8 })

        setContentView(layout)
    }

    private fun performLogout() {
        authPrefs.clearAuth()
        Toast.makeText(this, "Signed out", Toast.LENGTH_SHORT).show()
        navigateToLogin()
    }

    private fun performFullLogout() {
        authPrefs.clearAll()
        Toast.makeText(this, "Signed out and biometric settings cleared", Toast.LENGTH_SHORT).show()
        navigateToLogin()
    }

    private fun navigateToLogin() {
        val intent = Intent(this, LoginActivity::class.java)
        intent.flags = Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TASK
        startActivity(intent)
        finish()
    }
}